import{_ as l,o as e,c as i,ah as s}from"./chunks/framework.BrHDBe7t.js";const u=JSON.parse('{"title":"事件循环","description":"","frontmatter":{},"headers":[{"level":2,"title":"核心概念","slug":"核心概念","link":"#核心概念","children":[]},{"level":2,"title":"事件循环的组成","slug":"事件循环的组成","link":"#事件循环的组成","children":[{"level":3,"title":"调用栈（Call Stack）","slug":"调用栈-call-stack","link":"#调用栈-call-stack","children":[]},{"level":3,"title":"任务队列（Task Queue）","slug":"任务队列-task-queue","link":"#任务队列-task-queue","children":[]},{"level":3,"title":"Web APIs / C++ APIs","slug":"web-apis-c-apis","link":"#web-apis-c-apis","children":[]}]},{"level":2,"title":"宏任务（Macrotasks）","slug":"宏任务-macrotasks","link":"#宏任务-macrotasks","children":[]},{"level":2,"title":"微任务（Microtasks）","slug":"微任务-microtasks","link":"#微任务-microtasks","children":[]},{"level":2,"title":"事件循环执行顺序","slug":"事件循环执行顺序","link":"#事件循环执行顺序","children":[]}],"relativePath":"javascript/core/事件循环.md","filePath":"javascript/core/事件循环.md"}'),t={name:"javascript/core/事件循环.md"};function r(c,a,o,n,h,d){return e(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="事件循环" tabindex="-1">事件循环 <a class="header-anchor" href="#事件循环" aria-label="Permalink to “事件循环”">​</a></h1><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><p>JavaScript 是单线程的，这意味着它一次只能执行一个任务。事件循环（Event Loop）是 JavaScript 处理异步操作的机制，使得非阻塞 I/O 成为可能。</p><h2 id="事件循环的组成" tabindex="-1">事件循环的组成 <a class="header-anchor" href="#事件循环的组成" aria-label="Permalink to “事件循环的组成”">​</a></h2><h3 id="调用栈-call-stack" tabindex="-1">调用栈（Call Stack） <a class="header-anchor" href="#调用栈-call-stack" aria-label="Permalink to “调用栈（Call Stack）”">​</a></h3><ul><li>后进先出（LIFO）的数据结构</li><li>存储函数的执行上下文</li><li>同步任务按顺序执行</li></ul><h3 id="任务队列-task-queue" tabindex="-1">任务队列（Task Queue） <a class="header-anchor" href="#任务队列-task-queue" aria-label="Permalink to “任务队列（Task Queue）”">​</a></h3><ul><li>先进先出（FIFO）的数据结构</li><li>存储异步任务的回调函数</li><li>分为宏任务队列和微任务队列</li></ul><h3 id="web-apis-c-apis" tabindex="-1">Web APIs / C++ APIs <a class="header-anchor" href="#web-apis-c-apis" aria-label="Permalink to “Web APIs / C++ APIs”">​</a></h3><ul><li>浏览器提供的异步 API</li><li>Node.js 的 C++ 扩展</li></ul><p>例如：setTimeout、DOM 事件、AJAX、文件读写</p><h2 id="宏任务-macrotasks" tabindex="-1">宏任务（Macrotasks） <a class="header-anchor" href="#宏任务-macrotasks" aria-label="Permalink to “宏任务（Macrotasks）”">​</a></h2><ul><li>setTimeout、setInterval</li><li>setImmediate（Node.js）</li><li>I/O 操作</li><li>UI 渲染（浏览器）</li><li>requestAnimationFrame（浏览器）</li><li>script（整体代码）</li></ul><h2 id="微任务-microtasks" tabindex="-1">微任务（Microtasks） <a class="header-anchor" href="#微任务-microtasks" aria-label="Permalink to “微任务（Microtasks）”">​</a></h2><ul><li>Promise.then()、Promise.catch()、Promise.finally()</li><li>async/await</li><li>MutationObserver（浏览器）</li><li>process.nextTick（Node.js，优先级最高）</li><li>queueMicrotask()</li></ul><h2 id="事件循环执行顺序" tabindex="-1">事件循环执行顺序 <a class="header-anchor" href="#事件循环执行顺序" aria-label="Permalink to “事件循环执行顺序”">​</a></h2><ol><li>执行同步代码，这些代码会进入调用栈，直到栈为空。</li><li>处理微任务（microtasks）：在调用栈为空后，JavaScript引擎会检查微任务队列，并依次执行微任务，直到微任务队列为空。</li><li>执行渲染（如果需要）：在浏览器环境中，如果当前需要更新渲染，则会执行渲染操作。</li><li>从宏任务队列中取出一个任务执行。</li><li>重复步骤2到4。</li></ol>',17)])])}const m=l(t,[["render",r]]);export{u as __pageData,m as default};
